mapper.select:
SELECT 
FROM biz_order
WHERE is_deleted = 0
AND user_id = #{userId}
AND merchant_id = #{merchantId}
AND status = #{status}
ORDER BY create_time DESC

mapper.update:
UPDATE biz_order
status = #{status}, pay_type = #{payType}, pay_time = #{payTime}, deliver_time = #{deliverTime}, complete_time = #{completeTime}, cancel_reason = #{cancelReason}, cancel_time = #{cancelTime}, update_time = NOW()
WHERE id = #{id}
